<section class="grid cards"><?php foreach($counts as $label=>$count): ?><div class="card"><span><?= e(ucwords($label)) ?></span><strong><?= e($count) ?></strong></div><?php endforeach; ?><div class="card"><span>Projected Revenue</span><strong>₹<?= money($revenue) ?></strong></div></section><section class="grid two"><div class="card"><h3>Recent Quotations</h3><table><tr><th>No</th><th>Customer</th><th>Total</th></tr><?php foreach($recent as $r): ?><tr><td><?= e($r['quotation_number']) ?></td><td><?= e($r['company_name']) ?></td><td>₹<?= money($r['grand_total']) ?></td></tr><?php endforeach; ?></table></div><div class="card"><h3>Recent Activity</h3><?php foreach($logs as $l): ?><p><strong><?= e($l['event']) ?></strong> <?= e($l['subject_type']) ?> #<?= e($l['subject_id']) ?> by <?= e($l['user_name'] ?? 'System') ?></p><?php endforeach; ?></div></section>
